<?php
// Generated by Cursor prompt — module: Abonelik (SubscriptionController) — date: 2026-03-15

namespace App\Modules\Abonelik\Controllers;

use App\Http\Controllers\Controller;
use App\Modules\Abonelik\Models\SubscriptionPlan;
use App\Modules\Abonelik\Models\CompanySubscription;
use App\Modules\Abonelik\Models\Invoice;
use Illuminate\Http\Request;
use Illuminate\Http\JsonResponse;
use Illuminate\Support\Str;

class SubscriptionController extends Controller
{
    public function index()
    {
        $companyId   = auth()->user()->company_id;
        $subscription = CompanySubscription::forCompany($companyId)
            ->with('plan')
            ->latest()
            ->first();
        $plans = SubscriptionPlan::active()->get();
        return view('admin.abonelik.index', compact('subscription', 'plans'));
    }

    // ─── Planlar ─────────────────────────────────────────────────────────────

    public function plans(Request $request): mixed
    {
        $plans = SubscriptionPlan::active()->get();
        if ($request->expectsJson()) {
            return response()->json(['data' => $plans]);
        }
        return view('admin.abonelik.plans', compact('plans'));
    }

    public function storePlan(Request $request): JsonResponse
    {
        $this->authorize('subscription.manage');

        $data = $request->validate([
            'name'          => 'required|string|max:191',
            'slug'          => 'nullable|string|max:100|unique:subscription_plans',
            'description'   => 'nullable|string',
            'price_monthly' => 'required|numeric|min:0',
            'price_yearly'  => 'nullable|numeric|min:0',
            'currency'      => 'nullable|string|size:3',
            'max_personel'  => 'nullable|integer|min:1',
            'features'      => 'nullable|array',
            'is_popular'    => 'nullable|boolean',
            'is_active'     => 'nullable|boolean',
            'sort_order'    => 'nullable|integer',
        ]);

        $data['slug'] ??= Str::slug($data['name']);
        $plan = SubscriptionPlan::create($data);

        return response()->json(['success' => true, 'message' => 'Plan oluşturuldu.', 'data' => $plan], 201);
    }

    public function updatePlan(Request $request, SubscriptionPlan $plan): JsonResponse
    {
        $this->authorize('subscription.manage');

        $data = $request->validate([
            'name'          => 'sometimes|required|string',
            'description'   => 'nullable|string',
            'price_monthly' => 'sometimes|required|numeric|min:0',
            'price_yearly'  => 'nullable|numeric|min:0',
            'max_personel'  => 'nullable|integer',
            'features'      => 'nullable|array',
            'is_popular'    => 'nullable|boolean',
            'is_active'     => 'nullable|boolean',
            'sort_order'    => 'nullable|integer',
        ]);

        $plan->update($data);
        return response()->json(['success' => true, 'message' => 'Plan güncellendi.', 'data' => $plan->fresh()]);
    }

    public function destroyPlan(SubscriptionPlan $plan): JsonResponse
    {
        $this->authorize('subscription.manage');
        if ($plan->subscriptions()->whereIn('status', ['active', 'trial'])->exists()) {
            return response()->json(['success' => false, 'message' => 'Aktif abonelikleri olan plan silinemez.'], 422);
        }
        $plan->delete();
        return response()->json(['success' => true, 'message' => 'Plan silindi.']);
    }

    // ─── Abonelikler ──────────────────────────────────────────────────────────

    public function subscriptions(Request $request): JsonResponse
    {
        $this->authorize('subscription.manage');

        $subscriptions = CompanySubscription::with(['company', 'plan'])
            ->when($request->filled('status'), fn ($q) => $q->where('status', $request->status))
            ->orderByDesc('created_at')
            ->paginate($request->get('per_page', 20));

        return response()->json([
            'data'  => $subscriptions->map(fn ($s) => array_merge($s->toArray(), [
                'status_label'   => $s->status_label,
                'days_remaining' => $s->days_remaining,
                'is_active'      => $s->isActive(),
            ])),
            'total' => $subscriptions->total(),
        ]);
    }

    public function currentSubscription(): JsonResponse
    {
        $companyId = auth()->user()->company_id;
        $sub = CompanySubscription::forCompany($companyId)->with('plan')->latest()->first();

        return response()->json([
            'data' => $sub ? array_merge($sub->toArray(), [
                'status_label'   => $sub->status_label,
                'days_remaining' => $sub->days_remaining,
                'is_on_trial'    => $sub->isOnTrial(),
            ]) : null,
        ]);
    }

    public function upgrade(Request $request): JsonResponse
    {
        $this->authorize('subscription.manage');

        $data = $request->validate([
            'plan_id'       => 'required|exists:subscription_plans,id',
            'billing_cycle' => 'required|in:monthly,yearly',
        ]);

        $plan      = SubscriptionPlan::findOrFail($data['plan_id']);
        $companyId = auth()->user()->company_id;
        $price     = $data['billing_cycle'] === 'yearly' ? $plan->price_yearly : $plan->price_monthly;

        $sub = CompanySubscription::updateOrCreate(
            ['company_id' => $companyId],
            [
                'plan_id'       => $plan->id,
                'status'        => 'active',
                'billing_cycle' => $data['billing_cycle'],
                'price'         => $price,
                'started_at'    => now(),
                'ends_at'       => $data['billing_cycle'] === 'yearly' ? now()->addYear() : now()->addMonth(),
            ]
        );

        // Fatura oluştur
        Invoice::create([
            'company_id'    => $companyId,
            'subscription_id'=> $sub->id,
            'invoice_number'=> 'INV-' . strtoupper(Str::random(8)),
            'amount'        => $price,
            'tax_amount'    => $price * 0.20, // %20 KDV
            'total_amount'  => $price * 1.20,
            'currency'      => $plan->currency,
            'status'        => 'sent',
            'due_date'      => now()->addDays(30),
        ]);

        return response()->json(['success' => true, 'message' => "Paket {$plan->name} olarak güncellendi."]);
    }

    // ─── Faturalar ────────────────────────────────────────────────────────────

    public function invoices(Request $request): mixed
    {
        $companyId = auth()->user()->company_id;

        $invoices = Invoice::forCompany($companyId)
            ->when($request->filled('status'), fn ($q) => $q->where('status', $request->status))
            ->orderByDesc('created_at')
            ->paginate($request->get('per_page', 15));

        if ($request->expectsJson()) {
            return response()->json([
                'data'  => $invoices->map(fn ($i) => array_merge($i->toArray(), [
                    'status_label' => $i->status_label,
                    'status_color' => $i->status_color,
                ])),
                'total' => $invoices->total(),
            ]);
        }

        return view('admin.abonelik.invoices', compact('invoices'));
    }

    public function billing()
    {
        $companyId = auth()->user()->company_id;
        $subscription = CompanySubscription::forCompany($companyId)->with('plan')->latest()->first();
        $invoices = Invoice::forCompany($companyId)->latest()->take(12)->get();
        $plans = SubscriptionPlan::active()->get();
        return view('admin.abonelik.billing', compact('subscription', 'invoices', 'plans'));
    }
}
